const body = $input.first().json.body || $input.first().json;
const EXPECTED = 'bjh_NssQxwv-fbPZnSPI8fnzPmUX3Kbp1v3Ymy006w';
const token = String(body.token || '');
if (token !== EXPECTED) {
  return [{ json: { _error: 'token_invalido', http_code: 403 } }];
}
const action = String(body.action || '').toLowerCase().trim();
const valid_actions = ['create_lead', 'ajustar_saldo', 'asistencia', 'edit_nombre', 'edit_telefono'];
if (!valid_actions.includes(action)) {
  return [{ json: { _error: 'accion_invalida', http_code: 400 } }];
}
function normTel(raw) {
  let t = String(raw || '').replace(/\D/g, '');
  if (t.length === 10 && t[0] === '3') t = '57' + t;
  return t;
}
let tel = normTel(body.telefono);
if (tel.length < 10) return [{ json: { _error: 'telefono_invalido', http_code: 400 } }];
const nombre = String(body.nombre || '').trim();
const clases = (body.clases !== undefined && body.clases !== null && body.clases !== '') ? parseInt(body.clases, 10) : null;
const nuevo_telefono = normTel(body.nuevo_telefono);
if (action === 'create_lead' && nombre.length < 2) return [{ json: { _error: 'nombre_requerido', http_code: 400 } }];
if (action === 'edit_nombre' && nombre.length < 2) return [{ json: { _error: 'nombre_requerido', http_code: 400 } }];
if (action === 'edit_telefono' && nuevo_telefono.length < 10) return [{ json: { _error: 'nuevo_telefono_invalido', http_code: 400 } }];
if (action === 'edit_telefono' && nuevo_telefono === tel) return [{ json: { _error: 'tel_es_igual', http_code: 400 } }];
if (action === 'ajustar_saldo' && (clases === null || isNaN(clases) || clases < 0 || clases > 999)) return [{ json: { _error: 'cantidad_invalida', http_code: 400 } }];
const p1 = { action, telefono: tel, nombre, clases, nuevo_telefono };
return [{ json: { action, telefono: tel, nombre, clases, nuevo_telefono, p1_json: JSON.stringify(p1) } }];

const r = $input.first().json;
let message = '';
let ok = true;
const action = r.action;
if (action === 'create_lead') {
  if (r.lead_creado) {
    message = 'Lead creado: ' + (r.nombre_input || '') + ' (' + r.telefono + ')';
  } else if (r.lead_existe) {
    message = 'Ya existía: ' + (r.nombre_real || r.nombre_input || '') + ' (' + r.telefono + ')';
  } else {
    ok = false; message = 'No se pudo crear el lead';
  }
} else if (action === 'ajustar_saldo') {
  if (!r.lead_existe) { ok = false; message = 'Ese teléfono no existe como lead. Crea el lead primero.'; }
  else if (r.saldo_nuevo !== null && r.saldo_nuevo !== undefined) {
    message = 'Saldo de ' + (r.nombre_real || r.telefono) + ' ajustado a ' + r.saldo_nuevo + ' clase(s). Vence ' + r.vence_at_nuevo + '.';
  } else { ok = false; message = 'No se pudo ajustar el saldo'; }
} else if (action === 'asistencia') {
  if (!r.lead_existe) { ok = false; message = 'Ese teléfono no existe como lead. Crea el lead primero.'; }
  else if (r.asistencia_registrada) {
    if (r.era_deudor) {
      message = 'Asistencia registrada para ' + (r.nombre_real || r.telefono) + ' como DEUDOR (saldo en 0, no se descontó).';
    } else {
      message = 'Asistencia registrada para ' + (r.nombre_real || r.telefono) + '. Saldo: ' + r.saldo_despues_asistencia + ' clase(s) restantes.';
    }
  } else { ok = false; message = 'No se pudo registrar la asistencia'; }
} else if (action === 'edit_nombre') {
  if (r.edit_nombre_aplicado) {
    message = 'Nombre actualizado a: ' + r.edit_nombre_nuevo_nombre;
  } else if (!r.lead_existe) {
    ok = false; message = 'No encontré ese teléfono en la base.';
  } else {
    ok = false; message = 'No se pudo actualizar el nombre.';
  }
} else if (action === 'edit_telefono') {
  if (r.edit_tel_aplicado) {
    message = 'Teléfono actualizado. Todo el historial (saldos, asistencias, recargas, handoffs, mensajes) ahora apunta al nuevo número.';
  } else if (!r.edit_tel_old_existe) {
    ok = false; message = 'El teléfono original no existe en la base.';
  } else if (r.edit_tel_new_existe) {
    ok = false; message = 'El nuevo teléfono ya pertenece a otro cliente. Cambia el destino o elimina al duplicado primero.';
  } else {
    ok = false; message = 'No se pudo cambiar el teléfono.';
  }
}
return [{ json: { ok, message, action, telefono: r.telefono, nombre: r.nombre_real, saldo_nuevo: r.saldo_nuevo, saldo_despues_asistencia: r.saldo_despues_asistencia, era_deudor: r.era_deudor, lead_existe: r.lead_existe, lead_creado: r.lead_creado } }];
